"use client";

import * as AvatarPrimitive from "@radix-ui/react-avatar";
import { cn } from "@shery-ui/utils";
import * as React from "react";

const Avatar = React.forwardRef(({ className, size = "default", ...props }, ref) => (
  <AvatarPrimitive.Root
    ref={ref}
    data-size={size}
    className={cn(
      "group/avatar relative flex size-8 shrink-0 overflow-hidden rounded-full",
      "data-[size=sm]:size-6 data-[size=default]:size-8 data-[size=lg]:size-10",
      className
    )}
    {...props}
  />
));

const AvatarImage = React.forwardRef(({ className, ...props }, ref) => (
  <AvatarPrimitive.Image ref={ref} className={cn("aspect-square size-full", className)} {...props} />
));

const AvatarFallback = React.forwardRef(({ className, ...props }, ref) => (
  <AvatarPrimitive.Fallback
    ref={ref}
    className={cn("flex size-full items-center justify-center rounded-full bg-muted text-sm text-muted-foreground", className)}
    {...props}
  />
));

export { Avatar, AvatarFallback, AvatarImage };

